const input = $input.first().json;

const html =
  typeof input === 'string'
    ? input
    : (input.data ?? input.body ?? input.response ?? '');

if (typeof html !== 'string' || html.length < 100) {
  throw new Error('ไม่พบ HTML จาก Kingshot Wiki');
}

if (/Just a moment|cf-chl|Enable JavaScript and cookies/i.test(html)) {
  throw new Error('เว็บตอบกลับเป็น Cloudflare challenge');
}

function decodeHtml(value) {
  return value
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;|&apos;/gi, "'")
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>');
}

const text = decodeHtml(
  html
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>|<\/li>|<\/h[1-6]>|<\/div>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
)
  .replace(/\r/g, '')
  .replace(/[ \t]+/g, ' ')
  .replace(/\n{2,}/g, '\n')
  .trim();

const activeMatch = text.match(
  /Active\s+Codes?\s*:?\s*([\s\S]*?)(?:Concierge member codes|How to Redeem|Expired Codes?|Redeem Codes?)/i
);

if (!activeMatch) {
  return [{
    json: {
      ok: false,
      message: 'ไม่พบส่วน Active Codes อาจมีการเปลี่ยนโครงสร้างหน้าเว็บ',
      preview: text.slice(0, 1500),
      sourceUrl: 'https://kingshotwiki.com/giftcodes/',
      checkedAt: new Date().toISOString()
    }
  }];
}

const activeText = activeMatch[1];

const blocked = new Set([
  'ACTIVE', 'CODES', 'CODE', 'COPY', 'NEW', 'UPDATED',
  'KINGSHOT', 'GIFT', 'REDEEM', 'REWARDS'
]);

const candidates = activeText.match(/\b[A-Za-z0-9]{5,30}\b/g) ?? [];

const codes = [...new Set(candidates)]
  .filter(code => !blocked.has(code.toUpperCase()))
  .filter(code => !/^\d+$/.test(code))
  .filter(code => !/^(https?|www)$/i.test(code));

if (codes.length === 0) {
  return [{
    json: {
      ok: false,
      message: 'พบส่วน Active Codes แต่แยกโค้ดไม่สำเร็จ',
      activeSectionPreview: activeText.slice(0, 1000),
      sourceUrl: 'https://kingshotwiki.com/giftcodes/',
      checkedAt: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    ok: true,
    codes,
    source: 'Kingshot Wiki',
    sourceUrl: 'https://kingshotwiki.com/giftcodes/',
    checkedAt: new Date().toISOString()
  }
}];
